import React, {
    useEffect,
    useState
} from "react";

import HodLayout from "../../layouts/HodLayout";
import AnalyticsBarChart from "../../components/charts/BarChart";
import HodSummaryCards from "../../components/dashboard/HodSummaryCards";

import {
    getHodAnalytics
} from "../../api/analyticsApi";

function HodAnalytics() {

    const [data, setData] =
        useState(null);

    const [loading, setLoading] =
        useState(true);

    useEffect(() => {

        loadAnalytics();

    }, []);

    const loadAnalytics =
        async () => {

            try {

                const res =
                    await getHodAnalytics();

                setData(res.data);

            }

            catch (err) {

                console.log(err);

            }

            finally {

                setLoading(false);

            }

        };

    if (loading) {

        return (

            <HodLayout>

                <div
                    style={{
                        padding: "30px"
                    }}
                >

                    <h2>
                        Loading Analytics...
                    </h2>

                </div>

            </HodLayout>

        );

    }

    return (

        <HodLayout>

            <div
                style={{
                    padding: "30px",
                    background: "#f3f4f6",
                    minHeight: "100vh"
                }}
            >

                <h1
                    style={{
                        marginBottom: "20px"
                    }}
                >
                    📊 HOD Analytics
                </h1>

                <hr
                    style={{
                        marginBottom: "30px"
                    }}
                />

                {/* Summary Cards */}

                <HodSummaryCards
                    summary={data?.summary}
                />

                {/* Faculty List */}

                <div
                    style={{
                        background: "#fff",
                        borderRadius: "15px",
                        padding: "25px",
                        boxShadow:
                            "0 4px 12px rgba(0,0,0,.08)"
                    }}
                >

                    <h2
                        style={{
                            marginBottom: "20px"
                        }}
                    >
                        Faculty List
                    </h2>

                    <table
                        style={{
                            width: "100%",
                            borderCollapse: "collapse"
                        }}
                    >

                        <thead>

                            <tr
                                style={{
                                    background: "#2563eb",
                                    color: "#fff"
                                }}
                            >

                                <th
                                    style={{
                                        padding: "12px"
                                    }}
                                >
                                    Faculty Name
                                </th>

                                <th
                                    style={{
                                        padding: "12px"
                                    }}
                                >
                                    Email
                                </th>

                            </tr>

                        </thead>

                        <tbody>

                            {

                                data?.facultyList?.map(

                                    (faculty) => (

                                        <tr
                                            key={faculty._id}
                                        >

                                            <td
                                                style={{
                                                    padding: "12px",
                                                    borderBottom:
                                                        "1px solid #e5e7eb"
                                                }}
                                            >

                                                {faculty.name}

                                            </td>

                                            <td
                                                style={{
                                                    padding: "12px",
                                                    borderBottom:
                                                        "1px solid #e5e7eb"
                                                }}
                                            >

                                                {faculty.email}

                                            </td>

                                        </tr>

                                    )

                                )

                            }

                        </tbody>

                    </table>

                </div>

            </div>

        </HodLayout>

    );

}

export default HodAnalytics;
